import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: $('VEX_API_KEY').value!,
  projectId: 'cs-n8n-support',
});

// Store client in workflow context for reuse
$workflow.staticData.vexClient = vex;

return [{ json: { status: 'initialized', clientReady: true } }];

const vex = $workflow.staticData.vexClient;
const aiOutput = $json.aiResponse;

const result = await vex.verify({
  inputs: {
    customerQuery: $('Customer Query').value,
    agentResponse: aiOutput.response,
    orderId: aiOutput.toolParams?.orderId,
    conversationHistory: $json.memoryWindow
  },
  checks: ['response_accuracy', 'pii_filtering', 'tone_consistency'],
  context: {
    useCase: 'customer_support',
    crmSystem: 'zendesk',
    maxTokens: 2000
  }
});

if (!result.valid) {
  throw new Error(`Vex blocked: ${result.issues.join(', ')}`);
}

return [{ json: { verified: true, safeOutput: aiOutput } }];

const vex = $workflow.staticData.vexClient;
const toolCall = $json.toolCall;

const policyCheck = await vex.verify({
  inputs: {
    ticketSubject: toolCall.params.subject,
    ticketDescription: toolCall.params.description,
    customerEmail: toolCall.params.customerEmail,
    escalationKeywords: toolCall.params.escalation
  },
  checks: ['policy_compliance', 'pii_filtering', 'escalation_triggers'],
  context: {
    supportTier: 'premium',
    maxTicketLength: 5000,
    allowedEscalations: ['billing', 'technical']
  }
});

return policyCheck.valid ? 
  [{ json: { approved: true, params: toolCall.params } }] : 
  [{ json: { blocked: true, reason: policyCheck.issues } }];

const vex = $workflow.staticData.vexClient;
const memoryContext = $json.memoryWindow;

const contextCheck = await vex.verify({
  inputs: {
    currentQuery: $('Customer Query').value,
    memoryContext: memoryContext.slice(-5), // Last 5 exchanges
    timestamp: new Date().toISOString()
  },
  checks: ['response_accuracy'],
  context: {
    stalenessThreshold: '2h',
    relevanceScore: 0.7,
    conversationId: $json.sessionId
  }
});

return {
  json: {
    validContext: contextCheck.valid,
    filteredMemory: contextCheck.valid ? memoryContext : [],
    relevanceScore: contextCheck.metrics?.relevance
  }
};

