// n8n HTTP Request Node Configuration
const webhookUrl = 'https://api.vex.dev/v1/verify/webhook';

const body = {
  apiKey: $('VEX_API_KEY').value,
  inputs: {
    agentResponse: $('AI Agent').json.response,
    customerQuery: $('Webhook Trigger').json.body.query,
    toolCalls: $('AI Agent').json.tools
  },
  checks: ['response_accuracy', 'pii_filtering'],
  projectId: 'n8n-customer-support'
};

// Set in HTTP Request node
const response = await $http.request({
  method: 'POST',
  url: webhookUrl,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
  timeout: 5000
});

if (!response.data.valid) {
  return [{ json: { error: 'Vex verification failed', issues: response.data.issues } }];
}

return [{ json: { verified: true, output: $('AI Agent').json } }];

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

await vex.policies.create({
  name: 'n8n-customer-support-policy',
  projectId: 'cs-n8n-support',
  rules: {
    pii: {
      detect: ['email', 'phone', 'order_id'],
      action: 'redact'
    },
    tone: {
      required: ['professional', 'empathetic'],
      prohibited: ['aggressive', 'sarcastic']
    },
    escalation: {
      keywords: ['urgent', 'billing emergency'],
      action: 'flag_for_human'
    }
  },
  defaultChecks: ['response_accuracy', 'policy_compliance']
});

const vex = new Vex({ apiKey: $('VEX_API_KEY').value! });

const metrics = await vex.metrics.list({
  projectId: 'cs-n8n-support',
  timeRange: '24h',
  filters: {
    workflow: 'customer-support',
    checks: ['pii_filtering', 'policy_compliance']
  }
});

return {
  json: {
    totalVerifications: metrics.total,
    blockRate: metrics.block_rate,
    topIssues: metrics.top_issues,
    recentBlocks: metrics.recent.slice(0, 5)
  }
};
